#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#include "./../main.h"
#include "./../util/timer/timer.h"
#include "./kernel_cpu.h"

void kernel_cpu(par_str par_cpu,
                dim_str dim_cpu,
                box_str* box_cpu,
                FOUR_VECTOR* rv_cpu,
                fp* qv_cpu,
                FOUR_VECTOR* fv_cpu)
{
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	box_str* d_box_gpu;
	FOUR_VECTOR* d_rv_gpu;
	fp* d_qv_gpu;
	FOUR_VECTOR* d_fv_gpu;

	int bx;

	time0 = get_time();

	if (dim_cpu.cores_arg > 0) {
		omp_set_num_threads(dim_cpu.cores_arg);
	}

	time1 = get_time();

	d_box_gpu = (box_str*)malloc(dim_cpu.box_mem);
	d_rv_gpu = (FOUR_VECTOR*)malloc(dim_cpu.space_mem);
	d_qv_gpu = (fp*)malloc(dim_cpu.space_mem2);
	d_fv_gpu = (FOUR_VECTOR*)malloc(dim_cpu.space_mem);

	time2 = get_time();

	memcpy(d_box_gpu, box_cpu, dim_cpu.box_mem);
	memcpy(d_rv_gpu, rv_cpu, dim_cpu.space_mem);
	memcpy(d_qv_gpu, qv_cpu, dim_cpu.space_mem2);
	memcpy(d_fv_gpu, fv_cpu, dim_cpu.space_mem);

	time3 = get_time();

	#pragma omp parallel for schedule(static)
	for (bx = 0; bx < dim_cpu.number_boxes; bx++) {

		fp a2;
		long first_i;
		FOUR_VECTOR* rA;
		FOUR_VECTOR* fA;
		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];

		int k;
		int pointer;
		long first_j;
		FOUR_VECTOR* rB;
		fp* qB;
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		int wtx;
		int j;

		a2 = 2.0 * par_cpu.alpha * par_cpu.alpha;

		first_i = d_box_gpu[bx].offset;
		rA = &d_rv_gpu[first_i];
		fA = &d_fv_gpu[first_i];

		for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
			rA_shared[wtx] = rA[wtx];
		}

		for (k = 0; k < (1 + d_box_gpu[bx].nn); k++) {

			if (k == 0) {
				pointer = bx;
			}
			else {
				pointer = d_box_gpu[bx].nei[k - 1].number;
			}

			first_j = d_box_gpu[pointer].offset;
			rB = &d_rv_gpu[first_j];
			qB = &d_qv_gpu[first_j];

			for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rB_shared[wtx] = rB[wtx];
				qB_shared[wtx] = qB[wtx];
			}

			for (wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					fp r2;
					fp u2;
					fp vij;
					fp fs;
					fp fxij;
					fp fyij;
					fp fzij;
					THREE_VECTOR d;

					r2 = (fp)rA_shared[wtx].v + (fp)rB_shared[j].v -
						 (((fp)rA_shared[wtx].x * (fp)rB_shared[j].x) +
						  ((fp)rA_shared[wtx].y * (fp)rB_shared[j].y) +
						  ((fp)rA_shared[wtx].z * (fp)rB_shared[j].z));
					u2 = a2 * r2;
					vij = exp(-u2);
					fs = 2 * vij;

					d.x = (fp)rA_shared[wtx].x - (fp)rB_shared[j].x;
					fxij = fs * d.x;
					d.y = (fp)rA_shared[wtx].y - (fp)rB_shared[j].y;
					fyij = fs * d.y;
					d.z = (fp)rA_shared[wtx].z - (fp)rB_shared[j].z;
					fzij = fs * d.z;

					fA[wtx].v += (double)((fp)qB_shared[j] * vij);
					fA[wtx].x += (double)((fp)qB_shared[j] * fxij);
					fA[wtx].y += (double)((fp)qB_shared[j] * fyij);
					fA[wtx].z += (double)((fp)qB_shared[j] * fzij);
				}
			}
		}
	}

	time4 = get_time();

	memcpy(fv_cpu, d_fv_gpu, dim_cpu.space_mem);

	time5 = get_time();

	free(d_rv_gpu);
	free(d_qv_gpu);
	free(d_fv_gpu);
	free(d_box_gpu);

	time6 = get_time();

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");

	printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", 					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n",					(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);

	printf("%15.12f s, %15.12f % : GPU: KERNEL\n",						(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);

	printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n",				(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", 					(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time6-time0) / 1000000);
}
